mapper.insert:
	/**
	* SQL ID : com.study.work.learning.user.dao.UserDAO.insertUser
	* SQL 명: 사용자 등록
	*/
	INSERT INTO TB_USER (
	      USER_ID
	    , USER_NAME
	    , PASSWORD
	    , EMAIL
	    , USER_ROLE
	    , CREATED_DTTM
	    , UPDATED_DTTM
	    , IS_ACTIVE
    ) VALUES (
	      #{userId}
	    , #{userName}
	    , #{password}
	    , #{email}
	    , #{userRole}
	    , CURRENT_TIMESTAMP()
	    , CURRENT_TIMESTAMP()
	    , #{isActive}
	)
